+#!/usr/bin/env node
+
+const fs = require("fs");
+const path = require("path");
+
+const commitMessageFile = process.argv[2];
+
+if (!commitMessageFile) {
+  console.error("Missing commit message file path.");
+  process.exit(1);
+}
+
+const rawMessage = fs.readFileSync(path.resolve(commitMessageFile), "utf8");
+const message = rawMessage
+  .split("\n")
+  .find((line) => line.trim() && !line.trim().startsWith("#"))
+  ?.trim();
+
+const commitMessagePattern =
+  /^(feat|fix|refactor)\/[a-z0-9]+(?:-[a-z0-9]+)* : .+$/;
+
+if (!message || !commitMessagePattern.test(message)) {
+  console.error("Invalid commit message format.");
+  console.error("Expected: <feat/fix/refactor>/<feature-name> : action");
+  console.error("Example: feat/booking-flow : add hotel cancellation validation");
+  process.exit(1);
+}
+
+process.exit(0);
